USE manpower_mediator;
CREATE TABLE IF NOT EXISTS candidates(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,mobile VARCHAR(20) NOT NULL,email VARCHAR(150),address TEXT,job_type VARCHAR(120) NOT NULL,skills TEXT NOT NULL,experience VARCHAR(100),expected_salary DECIMAL(12,2),preferred_location VARCHAR(200),availability VARCHAR(50) DEFAULT 'Immediate',resume VARCHAR(255),status ENUM('new','under_review','verified','shortlisted','sent','selected','deployed','rejected') DEFAULT 'new',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS candidate_requirement_matches(id INT AUTO_INCREMENT PRIMARY KEY,requirement_id INT NOT NULL,candidate_id INT NOT NULL,status ENUM('shortlisted','sent','selected','deployed','rejected') DEFAULT 'shortlisted',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,UNIQUE KEY uq_requirement_candidate(requirement_id,candidate_id),FOREIGN KEY(requirement_id) REFERENCES requirements(id) ON DELETE CASCADE,FOREIGN KEY(candidate_id) REFERENCES candidates(id) ON DELETE CASCADE);
